#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideAlgorithm {
    /// Houdini Catmull-Clark
    HoudiniCatmullMinusClark = 0,
    /// Mantra-Compatible Catmull-Clark
    MantraMinusCompatibleCatmullMinusClark = 1,
    /// OpenSubdiv Catmull-Clark
    OpensubdivCatmullMinusClark = 2,
    OpensubdivLoop = 3,
    OpensubdivBilinear = 4,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideCloseholes {
    DoNotClose = 0,
    PullCracksClosed = 1,
    StitchCracksTogether = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideSurroundpoly {
    NoEdgeDivision = 0,
    DivideEdges = 1,
    Triangulate = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideVtxboundary {
    NoBoundaryInterpolation = 0,
    SharpenEdgesBoundaries = 1,
    SharpenEdgesAndCornerBoundaries = 2,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideFvarlinear {
    SmoothEverywhere = 0,
    SharpenCornersOnly = 1,
    SharpenEdgeAndCorners = 2,
    /// Sharpen Edge and Corners (Propagate Corners)
    SharpenEdgeAndCornersPropagateCorners = 3,
    SharpenBoundaries = 4,
    LinearEverywhere = 5,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideCreasemethod {
    Uniform = 0,
    Chaikin = 1,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum SopSubdivideTrianglesubd {
    /// Catmull-Clark Weights
    CatmullMinusClarkWeights = 0,
    SmoothTriangleWeights = 1,
}

